String[] tokens = pair.split("=", 2);
switch (tokens.length) {
case 1:
if (pair.charAt(0) == '=') {
params.add(new QueryParameter("", tokens[0]));
} else {
params.add(new QueryParameter(tokens[0], ""));
}
break;
case 2:
params.add(new QueryParameter(tokens[0], tokens[1]));
